/*
 * WARNING: Default credentials are admin/admin123.
 * These MUST be changed before any production deployment.
 * This is a local-prototype login system, not internet-facing security.
 */
#define DEFAULT_USERNAME "admin"
#define DEFAULT_PASSWORD "admin123"

#define RATE_LIMIT_MAX     5
#define RATE_LIMIT_WINDOW  30

/* --------------- Helpers --------------- */

static void url_decode(char *dst, const char *src)
{
    while (*src) {
        if (*src == '+') {
            *dst++ = ' ';
            src++;
        } else if (*src == '%' && src[1] && src[2]) {
            char hex[3] = {src[1], src[2], '\0'};
            *dst++ = (char)strtol(hex, NULL, 16);
            src += 3;
        } else {
            *dst++ = *src++;
        }
    }
    *dst = '\0';
}

/* Check that a string contains only printable UTF-8 characters (no control chars 0x00-0x1F except tab/newline) */
static bool is_valid_utf8_printable(const char *s, size_t max_len)
{
    if (!s || !s[0]) return false;
    size_t len = strnlen(s, max_len);
    if (len >= max_len) return false;
    for (size_t i = 0; i < len; i++) {
        unsigned char c = (unsigned char)s[i];
        if (c < 0x20 && c != '\t') return false;
    }
    return true;
}

/* Extract session token from Cookie header.
   WARNING: This is a local-prototype auth scheme.
   Session tokens are random but transmitted as plain cookies.
   Not secure against network sniffing on open Wi-Fi. */
static bool get_session_from_request(httpd_req_t *req, char *token_out, size_t token_len)
{
    size_t buf_len = httpd_req_get_hdr_value_len(req, "Cookie");
    if (buf_len <= 0) return false;

    char *cookie_buf = malloc(buf_len + 1);
    if (!cookie_buf) return false;

    if (httpd_req_get_hdr_value_str(req, "Cookie", cookie_buf, buf_len + 1) != ESP_OK) {
        free(cookie_buf);
        return false;
    }

    /* Simple parse: find "session=" */
    const char *start = strstr(cookie_buf, "session=");
    if (start) {
        start += 8; /* skip "session=" */
        const char *end = strchr(start, ';');
        size_t len = end ? (size_t)(end - start) : strlen(start);
        if (len >= token_len) len = token_len - 1;
        memcpy(token_out, start, len);
        token_out[len] = '\0';
        free(cookie_buf);
        return true;
    }
    free(cookie_buf);
    return false;
}

/* Auth check middleware - returns true if session is valid */
static bool require_auth(httpd_req_t *req)
{
    char token[SESSION_TOKEN_LEN] = {0};
    if (!get_session_from_request(req, token, sizeof(token))) return false;
    return session_validate(token);
}

/* Convert chip model enum to string */
static const char* chip_model_to_string(esp_chip_model_t model)
{
    switch (model) {
    case CHIP_ESP32:    return "ESP32";
    case CHIP_ESP32S2:  return "ESP32-S2";
    case CHIP_ESP32S3:  return "ESP32-S3";
    case CHIP_ESP32C2:  return "ESP32-C2";
    case CHIP_ESP32C3:  return "ESP32-C3";
    case CHIP_ESP32C5:  return "ESP32-C5";
    case CHIP_ESP32C6:  return "ESP32-C6";
    case CHIP_ESP32H2:  return "ESP32-H2";
    case CHIP_ESP32P4:  return "ESP32-P4";
    default:            return "Unknown";
    }
}

/* Format MAC address bytes to XX:XX:XX:XX:XX:XX string */
static void format_mac(const uint8_t *mac, char *out)
{
    snprintf(out, 18, "%02x:%02x:%02x:%02x:%02x:%02x",
             mac[0], mac[1], mac[2], mac[3], mac[4], mac[5]);
}

/* Check Origin/Referer to prevent cross-site POST (CSRF mitigation) */
static bool is_same_origin(httpd_req_t *req)
{
    size_t buf_len = httpd_req_get_hdr_value_len(req, "Origin");
    char buf[128] = {0};

    if (buf_len > 0 && buf_len < sizeof(buf) - 1) {
        httpd_req_get_hdr_value_str(req, "Origin", buf, sizeof(buf));
    } else {
        buf_len = httpd_req_get_hdr_value_len(req, "Referer");
        if (buf_len > 0 && buf_len < sizeof(buf) - 1) {
            httpd_req_get_hdr_value_str(req, "Referer", buf, sizeof(buf));
        }
    }

    if (buf[0] == '\0') {
        ESP_LOGW(TAG, "POST request without Origin/Referer header");
        return true;
    }

    const char *ap_ip = wifi_manager_get_ap_ip();
    if (ap_ip && strstr(buf, ap_ip)) return true;

    const char *sta_ip = wifi_manager_get_sta_ip();
    if (sta_ip && sta_ip[0] && strstr(buf, sta_ip)) return true;

    if (strstr(buf, "home1.local")) return true;

    ESP_LOGW(TAG, "Cross-origin POST blocked: %s", buf);
    return false;
}

/* Send JSON response */
static esp_err_t send_json(httpd_req_t *req, const char *json, const char *status)
{
    httpd_resp_set_type(req, "application/json");
    httpd_resp_set_status(req, status);
    httpd_resp_send(req, json, strlen(json));
    return ESP_OK;
}

/* Scan context for non-blocking callback */
typedef struct {
    SemaphoreHandle_t sem;
    wifi_scan_entry_t entries[WIFI_SCAN_MAX];
    int count;
} wifi_scan_ctx_t;

static void scan_complete_cb(void *user_ctx, wifi_scan_entry_t *entries, int count)
{
    wifi_scan_ctx_t *ctx = (wifi_scan_ctx_t *)user_ctx;
    ctx->count = (count > WIFI_SCAN_MAX) ? WIFI_SCAN_MAX : count;
    if (ctx->count > 0) {
        memcpy(ctx->entries, entries, ctx->count * sizeof(wifi_scan_entry_t));
    }
    xSemaphoreGive(ctx->sem);
}

/* Send a static embedded file */
static esp_err_t serve_static(httpd_req_t *req, const uint8_t *start, const uint8_t *end,
                              const char *mime_type)
{
    size_t len = (size_t)(end - start);
    httpd_resp_set_type(req, mime_type);
    httpd_resp_send(req, (const char *)start, len);
    return ESP_OK;
}

