/* POST /api/login */
static esp_err_t handle_api_login(httpd_req_t *req)
{
    static int s_login_attempts = 0;
    static int64_t s_login_block_until = 0;

    if (!is_same_origin(req)) {
        return send_json(req, "{\"ok\":false,\"error\":\"forbidden\"}", "403 Forbidden");
    }

    int64_t now = esp_timer_get_time() / 1000000;
    if (s_login_block_until > now) {
        char resp[128];
        int remaining = (int)(s_login_block_until - now);
        snprintf(resp, sizeof(resp), "{\"ok\":false,\"error\":\"rate_limited\",\"retry_after\":%d}", remaining);
        return send_json(req, resp, "429 Too Many Requests");
    }

    char body[256] = {0};
    int ret = httpd_req_recv(req, body, sizeof(body) - 1);
    if (ret <= 0) {
        return send_json(req, "{\"ok\":false,\"error\":\"empty_body\"}", "401 Unauthorized");
    }
    body[ret] = '\0';

    char username[64] = {0};
    char password[64] = {0};

    const char *user_start = strstr(body, "username=");
    if (user_start) {
        user_start += 9;
        const char *user_end = strchr(user_start, '&');
        size_t len = user_end ? (size_t)(user_end - user_start) : strlen(user_start);
        if (len > sizeof(username) - 1) len = sizeof(username) - 1;
        char tmp[64] = {0};
        memcpy(tmp, user_start, len);
        url_decode(username, tmp);

        const char *pass_start = strstr(body, "password=");
        if (pass_start) {
            pass_start += 9;
            const char *pass_end = strchr(pass_start, '&');
            len = pass_end ? (size_t)(pass_end - pass_start) : strlen(pass_start);
            if (len > sizeof(password) - 1) len = sizeof(password) - 1;
            char tmp2[64] = {0};
            memcpy(tmp2, pass_start, len);
            url_decode(password, tmp2);
        }
    } else {
        cJSON *root = cJSON_Parse(body);
        if (root) {
            cJSON *u = cJSON_GetObjectItem(root, "username");
            cJSON *p = cJSON_GetObjectItem(root, "password");
            if (u && cJSON_IsString(u)) {
                strncpy(username, u->valuestring, sizeof(username) - 1);
            }
            if (p && cJSON_IsString(p)) {
                strncpy(password, p->valuestring, sizeof(password) - 1);
            }
            cJSON_Delete(root);
        }
    }

    if (strlen(username) == 0 || strlen(password) == 0) {
        s_login_attempts++;
        if (s_login_attempts >= RATE_LIMIT_MAX) {
            s_login_block_until = now + RATE_LIMIT_WINDOW;
        }
        return send_json(req, "{\"ok\":false,\"error\":\"missing_fields\"}", "401 Unauthorized");
    }

    if (!is_valid_utf8_printable(username, sizeof(username)) ||
        !is_valid_utf8_printable(password, sizeof(password))) {
        return send_json(req, "{\"ok\":false,\"error\":\"invalid_input\"}", "400 Bad Request");
    }

    if (strcmp(username, DEFAULT_USERNAME) != 0 || strcmp(password, DEFAULT_PASSWORD) != 0) {
        ESP_LOGW(TAG, "Login failed");
        s_login_attempts++;
        if (s_login_attempts >= RATE_LIMIT_MAX) {
            s_login_block_until = now + RATE_LIMIT_WINDOW;
        }
        return send_json(req, "{\"ok\":false,\"error\":\"invalid_credentials\"}", "401 Unauthorized");
    }

    char token[SESSION_TOKEN_LEN] = {0};
    if (!session_create(username, token)) {
        return send_json(req, "{\"ok\":false,\"error\":\"session_error\"}", "500 Internal Server Error");
    }

    s_login_attempts = 0;
    s_login_block_until = 0;

    cJSON *resp = cJSON_CreateObject();
    cJSON_AddBoolToObject(resp, "ok", true);
    cJSON_AddStringToObject(resp, "username", username);
    char *json_str = cJSON_PrintUnformatted(resp);
    cJSON_Delete(resp);

    char cookie[128];
    snprintf(cookie, sizeof(cookie), "session=%s; Path=/; SameSite=Lax", token);
    httpd_resp_set_hdr(req, "Set-Cookie", cookie);

    ESP_LOGI(TAG, "Login success");
    esp_err_t result = send_json(req, json_str, "200 OK");
    free(json_str);
    return result;
}

/* POST /api/logout */
static esp_err_t handle_api_logout(httpd_req_t *req)
{
    if (!is_same_origin(req)) {
        return send_json(req, "{\"ok\":false,\"error\":\"forbidden\"}", "403 Forbidden");
    }

    char token[SESSION_TOKEN_LEN] = {0};
    if (get_session_from_request(req, token, sizeof(token))) {
        session_destroy(token);
    }

    /* Clear cookie */
    httpd_resp_set_hdr(req, "Set-Cookie",
        "session=; Path=/; Max-Age=0; SameSite=Lax");

    return send_json(req, "{\"ok\":true}", "200 OK");
}

/* GET /api/wifi/scan - protected, returns JSON scan results */
static esp_err_t handle_api_wifi_scan(httpd_req_t *req)
{
    if (!require_auth(req)) {
        return send_json(req, "{\"ok\":false,\"error\":\"unauthorized\"}", "401 Unauthorized");
    }

    wifi_scan_ctx_t ctx;
    ctx.sem = xSemaphoreCreateBinary();
    ctx.count = 0;
    if (!ctx.sem) {
        return send_json(req, "{\"ok\":false,\"error\":\"memory\"}", "500 Internal Server Error");
    }

    if (!wifi_manager_scan(&ctx, scan_complete_cb)) {
        vSemaphoreDelete(ctx.sem);
        return send_json(req, "{\"ok\":false,\"error\":\"scan_failed\"}", "200 OK");
    }

    if (xSemaphoreTake(ctx.sem, pdMS_TO_TICKS(5000)) != pdTRUE) {
        vSemaphoreDelete(ctx.sem);
        return send_json(req, "{\"ok\":false,\"error\":\"scan_timeout\"}", "200 OK");
    }
    vSemaphoreDelete(ctx.sem);

    cJSON *root = cJSON_CreateObject();
    cJSON_AddBoolToObject(root, "ok", true);
    cJSON *arr = cJSON_AddArrayToObject(root, "networks");
    for (int i = 0; i < ctx.count; i++) {
        cJSON *item = cJSON_CreateObject();
        cJSON_AddStringToObject(item, "ssid", ctx.entries[i].ssid);
        cJSON_AddNumberToObject(item, "rssi", ctx.entries[i].rssi);
        cJSON_AddStringToObject(item, "auth", ctx.entries[i].auth);
        cJSON_AddNumberToObject(item, "channel", ctx.entries[i].channel);
        cJSON_AddItemToArray(arr, item);
    }

    char *json_str = cJSON_PrintUnformatted(root);
    cJSON_Delete(root);
    httpd_resp_set_type(req, "application/json");
    httpd_resp_send(req, json_str, strlen(json_str));
    free(json_str);

    return ESP_OK;
}

/* POST /api/wifi/connect - protected, connect to given SSID */
static esp_err_t handle_api_wifi_connect(httpd_req_t *req)
{
    if (!require_auth(req)) {
        return send_json(req, "{\"ok\":false,\"error\":\"unauthorized\"}", "401 Unauthorized");
    }

    if (!is_same_origin(req)) {
        return send_json(req, "{\"ok\":false,\"error\":\"forbidden\"}", "403 Forbidden");
    }

    char body[512] = {0};
    int ret = httpd_req_recv(req, body, sizeof(body) - 1);
    if (ret <= 0) {
        return send_json(req, "{\"ok\":false,\"error\":\"empty_body\"}", "200 OK");
    }
    body[ret] = '\0';

    char ssid[64] = {0};
    char password[64] = {0};
    wifi_sta_ip_config_t ip_cfg = {0};
    bool has_static_ip = false;

    cJSON *root = cJSON_Parse(body);
    if (root) {
        cJSON *s = cJSON_GetObjectItem(root, "ssid");
        cJSON *p = cJSON_GetObjectItem(root, "password");
        if (s && cJSON_IsString(s)) {
            strncpy(ssid, s->valuestring, sizeof(ssid) - 1);
        }
        if (p && cJSON_IsString(p)) {
            strncpy(password, p->valuestring, sizeof(password) - 1);
        }
        cJSON *ip_item = cJSON_GetObjectItem(root, "ip");
        if (ip_item && cJSON_IsString(ip_item) && ip_item->valuestring[0]) {
            strncpy(ip_cfg.ip, ip_item->valuestring, sizeof(ip_cfg.ip) - 1);
            has_static_ip = true;
            cJSON *gw = cJSON_GetObjectItem(root, "gateway");
            if (gw && cJSON_IsString(gw)) {
                strncpy(ip_cfg.gateway, gw->valuestring, sizeof(ip_cfg.gateway) - 1);
            }
            cJSON *nm = cJSON_GetObjectItem(root, "netmask");
            if (nm && cJSON_IsString(nm)) {
                strncpy(ip_cfg.netmask, nm->valuestring, sizeof(ip_cfg.netmask) - 1);
            }
            cJSON *dns = cJSON_GetObjectItem(root, "dns");
            if (dns && cJSON_IsString(dns)) {
                strncpy(ip_cfg.dns, dns->valuestring, sizeof(ip_cfg.dns) - 1);
            }
        }
        cJSON_Delete(root);
    }

    if (strlen(ssid) == 0) {
        return send_json(req, "{\"ok\":false,\"error\":\"missing_ssid\"}", "200 OK");
    }

    if (strlen(ssid) > 32) {
        return send_json(req, "{\"ok\":false,\"error\":\"ssid_too_long\"}", "400 Bad Request");
    }

    if (!is_valid_utf8_printable(ssid, sizeof(ssid))) {
        return send_json(req, "{\"ok\":false,\"error\":\"invalid_ssid\"}", "400 Bad Request");
    }

    if (strlen(password) > 64) {
        return send_json(req, "{\"ok\":false,\"error\":\"password_too_long\"}", "400 Bad Request");
    }

    if (password[0] && !is_valid_utf8_printable(password, sizeof(password))) {
        return send_json(req, "{\"ok\":false,\"error\":\"invalid_password\"}", "400 Bad Request");
    }

    if (!wifi_manager_connect_sta(ssid, password, has_static_ip ? &ip_cfg : NULL)) {
        return send_json(req, "{\"ok\":false,\"error\":\"connect_error\"}", "200 OK");
    }

    vTaskDelay(pdMS_TO_TICKS(5000));

    cJSON *resp = cJSON_CreateObject();
    if (wifi_manager_is_sta_connected()) {
        cJSON_AddBoolToObject(resp, "ok", true);
        cJSON_AddStringToObject(resp, "ssid", wifi_manager_get_sta_ssid());
        cJSON_AddStringToObject(resp, "ip", wifi_manager_get_sta_ip());
    } else {
        cJSON_AddBoolToObject(resp, "ok", false);
        cJSON_AddStringToObject(resp, "error", "connection_failed");
        cJSON_AddStringToObject(resp, "ssid", ssid);
    }
    char *json_str = cJSON_PrintUnformatted(resp);
    cJSON_Delete(resp);
    esp_err_t result = send_json(req, json_str, "200 OK");
    free(json_str);
    return result;
}

/* POST /api/wifi/disconnect - protected, disconnect STA */
static esp_err_t handle_api_wifi_disconnect(httpd_req_t *req)
{
    if (!require_auth(req)) {
        return send_json(req, "{\"ok\":false,\"error\":\"unauthorized\"}", "401 Unauthorized");
    }

    if (!is_same_origin(req)) {
        return send_json(req, "{\"ok\":false,\"error\":\"forbidden\"}", "403 Forbidden");
    }

    if (!wifi_manager_disconnect_sta()) {
        return send_json(req, "{\"ok\":false,\"error\":\"disconnect_failed\"}", "200 OK");
    }

    return send_json(req, "{\"ok\":true}", "200 OK");
}

